=<!DOCTYPE html>
<html lang="zh-TW">
<head>
    <meta charset="UTF-8">
    <title>SecOps 智能情報編輯台</title>
    <style>
        :root { --primary: #0078d4; --bg: #f5f7f9; --text: #333; }
        body { font-family: 'Segoe UI', system-ui, sans-serif; background: var(--bg); color: var(--text); display: flex; gap: 20px; padding: 25px; height: 100vh; margin: 0; box-sizing: border-box; }
        .main-editor { flex: 3; background: white; padding: 25px; border-radius: 12px; box-shadow: 0 4px 20px rgba(0,0,0,0.08); display: flex; flex-direction: column; }
        h2 { margin-top: 0; font-size: 1.5rem; color: var(--primary); display: flex; align-items: center; gap: 10px; }
        textarea { flex-grow: 1; width: 100%; padding: 20px; border: 1px solid #d1d5db; border-radius: 8px; font-size: 16px; line-height: 1.7; resize: none; outline: none; transition: border 0.3s; background: #fff; }
        textarea:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(0,120,212,0.1); }
        .side-panel { flex: 1; background: white; padding: 25px; border-radius: 12px; box-shadow: 0 4px 20px rgba(0,0,0,0.08); min-width: 300px; display: flex; flex-direction: column; }
        h3 { margin-top: 0; border-bottom: 2px solid var(--bg); padding-bottom: 10px; }
        .customer-card { margin-bottom: 20px; }
        .label-row { display: flex; justify-content: space-between; margin-bottom: 8px; font-weight: 600; }
        .progress-container { background: #e5e7eb; border-radius: 10px; height: 12px; width: 100%; overflow: hidden; }
        .progress-fill { background: linear-gradient(90deg, #0078d4, #00bcf2); height: 100%; border-radius: 10px; transition: width 1.5s cubic-bezier(0.1, 0, 0.2, 1); }
        .copy-btn { margin-top: 20px; padding: 12px; background: var(--primary); color: white; border: none; border-radius: 6px; cursor: pointer; font-weight: bold; transition: opacity 0.2s; }
        .copy-btn:hover { opacity: 0.9; }
    </style>
</head>
<body>
    <div class="main-editor">
        <h2> 資安摘要手動校對</h2>
        <textarea id="summaryText">{{ $node["Code in JavaScript"].json.clean_summary }}</textarea>
        <button class="copy-btn" onclick="copyContent()"> 複製摘要到剪貼簿</button>
    </div>

<div class="side-panel">
    <h3> 客戶關聯度分析 (Top 20)</h3>
    <div id="chart-area">
        {{ 
            (function() {
                try {
                    // 1. 抓取 Python 輸出的 stdout
                    let raw = $node["customer similarity"].json.stdout;
                    if (!raw) return "<p>等待分析數據...</p>";

                    // 2. 清理 JSON (預防 Python 的 print 雜訊)
                    if (raw.includes("{")) {
                        raw = raw.substring(raw.indexOf("{"), raw.lastIndexOf("}") + 1);
                    }

                    const scores = JSON.parse(raw);

                    // 3. 排序與篩選：將物件轉為陣列 -> 降序排序 -> 取前 20 名
                    const sortedScores = Object.entries(scores)
                        .sort((a, b) => b[1] - a[1]) // 由大到小排序
                        .slice(0, 20);              // 只取前 20 筆

                    // 4. 生成 HTML 內容
                    return sortedScores.map(([name, score]) => `
                        <div class="customer-card">
                            <div class="label-row">
                                <span>${name}</span>
                                <span style="color:${score > 0.5 ? '#00ff88' : '#aaa'}">
                                    ${(score * 100).toFixed(2)}%
                                </span>
                            </div>
                            <div class="progress-container">
                                <div class="progress-fill" style="width: ${score * 100}%; 
                                     background: ${score > 0.5 ? 'linear-gradient(90deg, #00c6ff, #00ff88)' : '#555'}">
                                </div>
                            </div>
                        </div>
                    `).join('');
                } catch (e) {
                    return `<div style="color:#ff4444; padding:10px; border:1px solid #440000;">
                                 解析失敗：${e.message}<br>
                                <small>原始內容：${$node["customer similarity"].json.stdout}</small>
                            </div>`;
                }
            })()
        }}
    </div>
</div>
    <p style="font-size: 12px; color: #999; margin-top: auto;">數據來源：Word2Vec 語義相似度模型</p>
</div>
    <script>
        function copyContent() {
            const text = document.getElementById('summaryText').value;
            navigator.clipboard.writeText(text).then(() => {
                alert('摘要已複製！');
            });
        }
    </script>
</body>
</html>
